class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next
def partition_list(head, x):
    before = ListNode(0)
    after = ListNode(0)
    p, q = before, after
    cur = head
    while cur:
        if cur.val < x:
            p.next = cur
            p = p.next
        else:
            q.next = cur
            q = q.next
        cur = cur.next
    q.next = None
    p.next = after.next
    return before.next

